use eframe::egui; use crate::core::api::EditorAPI; struct EditorApp { api: EditorAPI } impl Default for EditorApp { fn default() -> Self { Self { api: EditorAPI::new("archivo.txt") } } } impl eframe::App for EditorApp { fn update(&mut self, ctx: &egui::Context, _frame: &mut eframe::Frame) { egui::CentralPanel::default().show(ctx, |ui| { ui.heading("Editor de Código"); let buffer = self.api.buffers.get_mut(&self.api.active_buffer).unwrap(); if ui.add(egui::TextEdit::multiline(&mut buffer.lines[0])).changed() { self.api.notify(crate::core::events::EditorEvent::TextChanged); } }); } }
